    let data = { data: { me: { name: "", roles: [] } } };
    try {
      const bodyResult = await browserView.webContents.debugger.sendCommand(
        "Fetch.getResponseBody", { requestId: params.requestId }
      );
      const raw = bodyResult.base64Encoded
        ? Buffer.from(bodyResult.body, "base64").toString("utf8")
        : bodyResult.body;
      try { data = JSON.parse(raw); } catch (_parseErr) {}
    } catch (_bodyErr) {}
    if (!data || typeof data !== "object") data = {};
    if (!data.data) data.data = {};
    if (!data.data.me) data.data.me = { name: "", roles: [] };
    if (!Array.isArray(data.data.me.roles)) data.data.me.roles = [];
    if (!data.data.me.roles.some((r) => r.code === "PRO_SUBSCRIBER"))
      data.data.me.roles.push({ code: "PRO_SUBSCRIBER" });
    delete data.errors;
    browserView.webContents.debugger
      .sendCommand("Fetch.fulfillRequest", {
        requestId: params.requestId,
        responseCode: 200,
        body: Buffer.from(JSON.stringify(data)).toString("base64"),
      })
      .catch(() => {
        browserView.webContents.debugger
          .sendCommand("Fetch.continueRequest", { requestId: params.requestId })
          .catch(() => {});
      });
  });
